Multi-environment CORS requires careful configuration to avoid security gaps. A common vulnerability is using wildcard subdomains or reflecting the Origin header without validation, which attackers exploit through subdomain takeover.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Cors.Infrastructure;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;

namespace ProductionApi
{
    public class Startup
    {
        private readonly IConfiguration _configuration;
        private readonly IWebHostEnvironment _environment;

        public Startup(IConfiguration configuration, IWebHostEnvironment environment)
        {
            _configuration = configuration;
            _environment = environment;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            services.AddSingleton<ICorsValidator, SecureCorsValidator>();

            services.AddCors(options =>
            {
                options.AddPolicy("ProductionPolicy", builder =>
                {
                    ConfigureCorsPolicy(builder);
                });
            });

            services.AddControllers();
            services.AddHealthChecks();
        }

        private void ConfigureCorsPolicy(CorsPolicyBuilder builder)
        {
            var corsConfig = _configuration.GetSection("Cors");
            var allowedOrigins = corsConfig.GetSection("AllowedOrigins").Get<string[]>() ?? Array.Empty<string>();

            if (_environment.IsDevelopment())
            {
                // Development: Include localhost origins
                var devOrigins = corsConfig.GetSection("DevelopmentOrigins").Get<string[]>() ?? Array.Empty<string>();
                allowedOrigins = allowedOrigins.Concat(devOrigins).ToArray();
            }

            builder.WithOrigins(allowedOrigins)
                   .WithMethods("GET", "POST", "PUT", "DELETE", "PATCH")
                   .WithHeaders("Content-Type", "Authorization", "X-Request-ID")
                   .WithExposedHeaders("X-Pagination", "X-Request-ID")
                   .AllowCredentials()
                   .SetPreflightMaxAge(TimeSpan.FromMinutes(10));
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            // Custom middleware for enhanced CORS validation
            app.UseMiddleware<CorsValidationMiddleware>();

            app.UseCors("ProductionPolicy");

            // Security headers
            app.Use(async (context, next) =>
            {
                context.Response.Headers.Add("X-Content-Type-Options", "nosniff");
                context.Response.Headers.Add("X-Frame-Options", "DENY");
                context.Response.Headers.Add("Referrer-Policy", "strict-origin-when-cross-origin");
                await next();
            });

            app.UseAuthentication();
            app.UseAuthorization();
            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
                endpoints.MapHealthChecks("/health");
            });
        }
    }

    public interface ICorsValidator
    {
        bool IsValidOrigin(string origin);
    }

    public class SecureCorsValidator : ICorsValidator
    {
        private readonly HashSet<string> _allowedOrigins;
        private readonly ILogger<SecureCorsValidator> _logger;

        public SecureCorsValidator(IConfiguration configuration, ILogger<SecureCorsValidator> logger)
        {
            _logger = logger;
            _allowedOrigins = new HashSet<string>(
                configuration.GetSection("Cors:AllowedOrigins").Get<string[]>() ?? Array.Empty<string>(),
                StringComparer.OrdinalIgnoreCase
            );
        }

        public bool IsValidOrigin(string origin)
        {
            if (string.IsNullOrEmpty(origin))
                return false;

            // Exact match only - no wildcard or regex
            var isValid = _allowedOrigins.Contains(origin);

            if (!isValid)
            {
                _logger.LogWarning(
                    "CORS blocked: Unauthorized origin {Origin} attempted access",
                    origin
                );
            }

            return isValid;
        }
    }

    public class CorsValidationMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly ICorsValidator _corsValidator;
        private readonly ILogger<CorsValidationMiddleware> _logger;

        public CorsValidationMiddleware(
            RequestDelegate next,
            ICorsValidator corsValidator,
            ILogger<CorsValidationMiddleware> logger)
        {
            _next = next;
            _corsValidator = corsValidator;
            _logger = logger;
        }

        public async Task InvokeAsync(HttpContext context)
        {
            var origin = context.Request.Headers["Origin"].FirstOrDefault();

            if (!string.IsNullOrEmpty(origin))
            {
                if (!_corsValidator.IsValidOrigin(origin))
                {
                    // Log suspicious activity
                    _logger.LogWarning(
                        "Potential CORS attack blocked. Origin: {Origin}, IP: {IP}, Path: {Path}, UserAgent: {UserAgent}",
                        origin,
                        context.Connection.RemoteIpAddress,
                        context.Request.Path,
                        context.Request.Headers["User-Agent"].FirstOrDefault()
                    );

                    context.Response.StatusCode = StatusCodes.Status403Forbidden;
                    await context.Response.WriteAsJsonAsync(new { error = "Origin not allowed" });
                    return;
                }
            }

            await _next(context);
        }
    }
}
```

