from functools import wraps
import re
import logging
import time
from datetime import datetime
import hashlib

app = Flask(__name__)
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger('cors_security')

# Production CORS configuration
class CORSConfig:
    # Explicit subdomain allowlist - NOT regex patterns
    ALLOWED_SUBDOMAINS = {
        'example.com': ['app', 'api', 'admin', 'staging', 'www'],
        'trusted-partner.com': ['api']
    }

    # Explicit full origin allowlist for non-subdomain origins
    ALLOWED_ORIGINS = [
        'https://mobile.example.com',
        'https://partners.example.com'
    ]

    # Allowed methods per endpoint category
    ALLOWED_METHODS = {
        'read_only': ['GET', 'HEAD', 'OPTIONS'],
        'read_write': ['GET', 'POST', 'PUT', 'OPTIONS'],
        'admin': ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS']
    }

    # Allowed headers - explicit list, no wildcards
    ALLOWED_HEADERS = [
        'Content-Type',
        'Authorization',
        'X-Request-ID',
        'X-CSRF-Token'
    ]

    # Headers that can be exposed to JavaScript
    EXPOSE_HEADERS = [
        'X-Request-ID',
        'X-RateLimit-Remaining'
    ]

    # Pre-flight cache duration (1 hour)
    MAX_AGE = 3600


class CORSValidator:
    """Secure CORS origin validation with subdomain support"""

    def __init__(self, config: CORSConfig):
        self.config = config
        self._compile_patterns()

    def _compile_patterns(self):
        """Pre-compile validation patterns for performance"""
        self.subdomain_patterns = {}
        for domain, subdomains in self.config.ALLOWED_SUBDOMAINS.items():
            # Create explicit pattern for each allowed subdomain
            # SECURE: No wildcards in regex - explicit subdomain list
            escaped_domain = re.escape(domain)
            subdomain_pattern = '|'.join(re.escape(s) for s in subdomains)
            pattern = rf'^https://({subdomain_pattern})\.{escaped_domain}$'
            self.subdomain_patterns[domain] = re.compile(pattern)

    def is_origin_allowed(self, origin: str) -> bool:
        """Validate origin with strict security checks"""
        if not origin:
            return False

        # Normalize origin
        origin = origin.lower().strip()

        # Check explicit allowlist first
        if origin in [o.lower() for o in self.config.ALLOWED_ORIGINS]:
            return True

        # Check subdomain patterns
        for domain, pattern in self.subdomain_patterns.items():
            if pattern.match(origin):
                return True

        return False

    def validate_origin_security(self, origin: str) -> dict:
        """Extended validation with security metadata"""
        result = {
            'allowed': False,
            'origin': origin,
            'reason': None,
            'trust_level': 'untrusted'
        }

        if not origin:
            result['reason'] = 'missing_origin'
            return result

        # Block null origins (potential attack vector)
        if origin.lower() == 'null':
            result['reason'] = 'null_origin_blocked'
            return result

        # Validate URL structure
        if not origin.startswith('https://'):
            result['reason'] = 'https_required'
            return result

        if self.is_origin_allowed(origin):
            result['allowed'] = True
            result['trust_level'] = 'trusted'
            result['reason'] = 'allowlist_match'
        else:
            result['reason'] = 'not_in_allowlist'

        return result


# Initialize validator
cors_config = CORSConfig()
cors_validator = CORSValidator(cors_config)


def cors_protected(endpoint_type='read_only'):
    """Decorator for CORS-protected endpoints"""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            g.cors_endpoint_type = endpoint_type
            return f(*args, **kwargs)
        return decorated_function
    return decorator


@app.before_request
def handle_preflight():
    """Handle OPTIONS pre-flight requests"""
    if request.method == 'OPTIONS':
        origin = request.headers.get('Origin')
        validation = cors_validator.validate_origin_security(origin)

        if not validation['allowed']:
            logger.warning(
                f"Blocked pre-flight from {origin}: {validation['reason']}",
                extra={
                    'remote_addr': request.remote_addr,
                    'origin': origin,
                    'user_agent': request.headers.get('User-Agent')
                }
            )
            return '', 403

        response = app.make_response('')
        response.status_code = 204
        return response


@app.after_request
def add_cors_headers(response):
    """Add CORS headers to responses"""
    origin = request.headers.get('Origin')

    if not origin:
        return response

    validation = cors_validator.validate_origin_security(origin)

    if validation['allowed']:
        # Set CORS headers for trusted origins
        response.headers['Access-Control-Allow-Origin'] = origin
        response.headers['Access-Control-Allow-Credentials'] = 'true'

        # Get endpoint type from request context
        endpoint_type = getattr(g, 'cors_endpoint_type', 'read_only')
        allowed_methods = cors_config.ALLOWED_METHODS.get(endpoint_type, ['GET', 'OPTIONS'])

        response.headers['Access-Control-Allow-Methods'] = ', '.join(allowed_methods)
        response.headers['Access-Control-Allow-Headers'] = ', '.join(cors_config.ALLOWED_HEADERS)
        response.headers['Access-Control-Expose-Headers'] = ', '.join(cors_config.EXPOSE_HEADERS)
        response.headers['Access-Control-Max-Age'] = str(cors_config.MAX_AGE)
    else:
        # Log blocked requests for security monitoring
        logger.warning(
            f"CORS blocked for {origin}: {validation['reason']}",
            extra={
                'endpoint': request.endpoint,
                'method': request.method,
                'remote_addr': request.remote_addr
            }
        )

    # Always set Vary header for proper caching
    response.headers['Vary'] = 'Origin'

    # Additional security headers
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'

    return response


