Multi-environment CORS configuration requires careful handling to avoid accidentally allowing insecure origins in production. Dynamic subdomain support needs pattern validation to prevent subdomain takeover attacks.

**PRODUCTION PATTERN**:

```java
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.env.Environment;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.http.HttpServletRequest;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

@Configuration
public class ProductionCorsConfig {

    private static final Logger logger = LoggerFactory.getLogger(ProductionCorsConfig.class);

    private final Environment environment;

    @Value("${cors.allowed-origins:}")
    private List<String> configuredOrigins;

    @Value("${cors.subdomain-pattern:}")
    private String subdomainPattern;

    // Compiled pattern for subdomain validation
    private Pattern allowedSubdomainPattern;

    public ProductionCorsConfig(Environment environment) {
        this.environment = environment;
    }

    @Bean
    public CorsFilter corsFilter() {
        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/api/**", createCorsConfiguration());
        return new CorsFilter(source);
    }

    private CorsConfiguration createCorsConfiguration() {
        CorsConfiguration config = new CorsConfiguration();

        // Environment-specific origin handling
        if (isProductionEnvironment()) {
            // PRODUCTION: Strict whitelist only
            config.setAllowedOrigins(getProductionOrigins());
            logger.info("CORS configured for PRODUCTION with {} origins", 
                       getProductionOrigins().size());
        } else if (isStagingEnvironment()) {
            // STAGING: Staging + production origins
            config.setAllowedOrigins(getStagingOrigins());
            logger.info("CORS configured for STAGING");
        } else {
            // DEVELOPMENT: Allow localhost variations
            config.setAllowedOriginPatterns(getDevelopmentPatterns());
            logger.warn("CORS configured for DEVELOPMENT - NOT FOR PRODUCTION USE");
        }

        // Common secure settings
        config.setAllowedHeaders(Arrays.asList(
            "Authorization",
            "Content-Type",
            "X-Requested-With",
            "X-CSRF-Token"
        ));
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));
        config.setAllowCredentials(true);
        config.setMaxAge(3600L);
        config.setExposedHeaders(Arrays.asList("X-Request-Id", "X-RateLimit-Remaining"));

        return config;
    }

    private boolean isProductionEnvironment() {
        return Arrays.asList(environment.getActiveProfiles()).contains("prod");
    }

    private boolean isStagingEnvironment() {
        return Arrays.asList(environment.getActiveProfiles()).contains("staging");
    }

    private List<String> getProductionOrigins() {
        return Arrays.asList(
            "https://app.example.com",
            "https://admin.example.com",
            "https://mobile.example.com"
        );
    }

    private List<String> getStagingOrigins() {
        List<String> origins = new java.util.ArrayList<>(getProductionOrigins());
        origins.add("https://staging.example.com");
        origins.add("https://test.example.com");
        return origins;
    }

    private List<String> getDevelopmentPatterns() {
        return Arrays.asList(
            "http://localhost:[*]",
            "http://127.0.0.1:[*]"
        );
    }
}
```

