```java
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import javax.servlet.http.HttpServletRequest;
import java.util.regex.Pattern;
import java.util.regex.Matcher;

@Configuration
public class DynamicCorsConfig implements CorsConfigurationSource {

    private static final Logger logger = LoggerFactory.getLogger(DynamicCorsConfig.class);

    // SECURE: Pattern validates subdomain format and parent domain
    // Only allows alphanumeric subdomains of exactly example.com
    private static final Pattern ALLOWED_SUBDOMAIN_PATTERN = 
        Pattern.compile("^https://([a-z0-9-]+)\\.example\\.com$");

    // Blocklist for known-dangerous subdomains
    private static final List<String> BLOCKED_SUBDOMAINS = Arrays.asList(
        "admin", "api", "internal", "staging", "test", "dev"
    );

    @Override
    public CorsConfiguration getCorsConfiguration(HttpServletRequest request) {
        String origin = request.getHeader("Origin");

        if (origin == null || origin.isEmpty()) {
            return null; // No CORS needed for same-origin requests
        }

        // Validate origin against allowed pattern
        if (!isAllowedOrigin(origin)) {
            logger.warn("CORS request blocked from unauthorized origin: {}", 
                       sanitizeForLog(origin));
            return null; // Reject unauthorized origins
        }

        logger.debug("CORS request allowed from origin: {}", sanitizeForLog(origin));

        CorsConfiguration config = new CorsConfiguration();
        config.addAllowedOrigin(origin); // Add the validated origin
        config.setAllowedHeaders(Arrays.asList(
            "Authorization", "Content-Type", "X-Requested-With"
        ));
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE"));
        config.setAllowCredentials(true);
        config.setMaxAge(3600L);

        return config;
    }

    private boolean isAllowedOrigin(String origin) {
        // Check static whitelist first
        if (getStaticWhitelist().contains(origin)) {
            return true;
        }

        // Validate against subdomain pattern
        Matcher matcher = ALLOWED_SUBDOMAIN_PATTERN.matcher(origin);
        if (matcher.matches()) {
            String subdomain = matcher.group(1);

            // Check against blocked subdomains
            if (BLOCKED_SUBDOMAINS.contains(subdomain.toLowerCase())) {
                logger.warn("Blocked subdomain access attempt: {}", subdomain);
                return false;
            }

            // Additional validation: length limit, no consecutive hyphens
            if (subdomain.length() > 63 || subdomain.contains("--")) {
                return false;
            }

            return true;
        }

        return false;
    }

    private List<String> getStaticWhitelist() {
        return Arrays.asList(
            "https://app.example.com",
            "https://www.example.com"
        );
    }

    // Prevent log injection
    private String sanitizeForLog(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "_")
                    .substring(0, Math.min(input.length(), 200));
    }
}
```

