func secureCORSMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		origin := r.Header.Get("Origin")

		// SECURE: Only allow explicitly whitelisted origins
		if origin != "" && allowedOrigins[origin] {
			w.Header().Set("Access-Control-Allow-Origin", origin)
			w.Header().Set("Access-Control-Allow-Credentials", "true")
			w.Header().Set("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
			w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
			w.Header().Set("Access-Control-Max-Age", "86400")
		} else if origin != "" {
			// Log rejected origins for security monitoring
			log.Printf("CORS: Rejected origin %s for %s %s", origin, r.Method, r.URL.Path)
		}

		// SECURE: Set Vary header to prevent cache poisoning
		w.Header().Set("Vary", "Origin")

		if r.Method == "OPTIONS" {
			if !allowedOrigins[origin] {
				w.WriteHeader(http.StatusForbidden)
				return
			}
			w.WriteHeader(http.StatusNoContent)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func getUserProfile(w http.ResponseWriter, r *http.Request) {
	profile := UserProfile{
		ID:       12345,
		Username: "user",
		Email:    "user@example.com",
		Balance:  50000.00,
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(profile)
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/api/profile", getUserProfile)
	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", secureCORSMiddleware(mux)))
}
```

**Key Security Controls**:
- **Origin whitelist**: Only explicitly allowed origins can make credentialed requests
- **Vary header**: Prevents cache poisoning attacks where cached responses could leak to other origins
- **Security logging**: Rejected origins are logged for monitoring and alerting
- **Minimal headers**: Only necessary methods and headers are allowed

Dynamic subdomain validation requires careful pattern matching to prevent bypasses. Here's a production-ready implementation with proper security controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"
)

type CORSConfig struct {
	AllowedOrigins      []string          // Exact matches
	AllowedPatterns     []*regexp.Regexp  // Pattern matches for subdomains
	AllowedMethods      []string
	AllowedHeaders      []string
	ExposedHeaders      []string
	MaxAge              int
	AllowCredentials    bool
	EnableAuditLogging  bool
}

type SecurityAuditLog struct {
	Timestamp     time.Time `json:"timestamp"`
	Action        string    `json:"action"`
	Origin        string    `json:"origin"`
	RequestPath   string    `json:"request_path"`
	RequestMethod string    `json:"request_method"`
	ClientIP      string    `json:"client_ip"`
	UserAgent     string    `json:"user_agent"`
	Allowed       bool      `json:"allowed"`
	Reason        string    `json:"reason,omitempty"`
}

func NewCORSConfig() *CORSConfig {
	return &CORSConfig{
		AllowedOrigins: []string{
			"https://app.example.com",
			"https://admin.example.com",
		},
		AllowedPatterns: []*regexp.Regexp{
			// SECURE: Anchored regex with proper escaping
			// Matches: https://{customer}.app.example.com
			regexp.MustCompile(`^https://[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?\.app\.example\.com$`),
			// Matches: https://{customer}.api.example.com
			regexp.MustCompile(`^https://[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?\.api\.example\.com$`),
		},
		AllowedMethods:     []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
		AllowedHeaders:     []string{"Content-Type", "Authorization", "X-Request-ID"},
		ExposedHeaders:     []string{"X-Request-ID", "X-RateLimit-Remaining"},
		MaxAge:             86400,
		AllowCredentials:   true,
		EnableAuditLogging: true,
	}
}

func (c *CORSConfig) IsOriginAllowed(origin string) (bool, string) {
	if origin == "" {
		return false, "empty_origin"
	}

	// Validate origin is a proper URL
	parsedURL, err := url.Parse(origin)
	if err != nil {
		return false, "invalid_url_format"
	}

	// SECURE: Reject non-HTTPS in production (except localhost for dev)
	if parsedURL.Scheme != "https" {
		if !(parsedURL.Scheme == "http" && strings.HasPrefix(parsedURL.Host, "localhost")) {
			return false, "non_https_rejected"
		}
	}

	// SECURE: Reject origins with paths, queries, or fragments
	if parsedURL.Path != "" && parsedURL.Path != "/" {
		return false, "origin_has_path"
	}
	if parsedURL.RawQuery != "" || parsedURL.Fragment != "" {
		return false, "origin_has_query_or_fragment"
	}

	// Normalize origin (remove trailing slash, lowercase)
	normalizedOrigin := strings.ToLower(strings.TrimSuffix(origin, "/"))

	// Check exact matches first
	for _, allowed := range c.AllowedOrigins {
		if normalizedOrigin == strings.ToLower(allowed) {
			return true, "exact_match"
		}
	}

	// Check pattern matches
	for i, pattern := range c.AllowedPatterns {
		if pattern.MatchString(normalizedOrigin) {
			return true, "pattern_match_" + string(rune('0'+i))
		}
	}

	return false, "no_match"
}

func (c *CORSConfig) logAuditEvent(r *http.Request, origin string, allowed bool, reason string) {
	if !c.EnableAuditLogging {
		return
	}

	event := SecurityAuditLog{
		Timestamp:     time.Now().UTC(),
		Action:        "cors_check",
		Origin:        origin,
		RequestPath:   r.URL.Path,
		RequestMethod: r.Method,
		ClientIP:      getClientIP(r),
		UserAgent:     r.UserAgent(),
		Allowed:       allowed,
		Reason:        reason,
	}

	// In production, send to SIEM/logging service
	eventJSON, _ := json.Marshal(event)
	if allowed {
		log.Printf("CORS_AUDIT: %s", eventJSON)
	} else {
		log.Printf("CORS_BLOCKED: %s", eventJSON)
	}
}

func getClientIP(r *http.Request) string {
	// Check standard proxy headers
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		return strings.TrimSpace(ips[0])
	}
	if xri := r.Header.Get("X-Real-IP"); xri != "" {
		return xri
	}
	return strings.Split(r.RemoteAddr, ":")[0]
}

func ProductionCORSMiddleware(config *CORSConfig) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			origin := r.Header.Get("Origin")

			// Always set Vary header to prevent cache poisoning
			w.Header().Add("Vary", "Origin")
			w.Header().Add("Vary", "Access-Control-Request-Method")
			w.Header().Add("Vary", "Access-Control-Request-Headers")

			// No origin header means same-origin request or non-browser client
			if origin == "" {
				next.ServeHTTP(w, r)
				return
			}

			allowed, reason := config.IsOriginAllowed(origin)
			config.logAuditEvent(r, origin, allowed, reason)

			if !allowed {
				// Don't set any CORS headers for disallowed origins
				if r.Method == "OPTIONS" {
					w.WriteHeader(http.StatusForbidden)
					return
				}
				// Still process the request but without CORS headers
				// Browser will block the response
				next.ServeHTTP(w, r)
				return
			}

			// Set CORS headers for allowed origins
			w.Header().Set("Access-Control-Allow-Origin", origin)

			if config.AllowCredentials {
				w.Header().Set("Access-Control-Allow-Credentials", "true")
			}

			if len(config.ExposedHeaders) > 0 {
				w.Header().Set("Access-Control-Expose-Headers",
					strings.Join(config.ExposedHeaders, ", "))
			}

			// Handle preflight requests
			if r.Method == "OPTIONS" {
				w.Header().Set("Access-Control-Allow-Methods",
					strings.Join(config.AllowedMethods, ", "))
				w.Header().Set("Access-Control-Allow-Headers",
					strings.Join(config.AllowedHeaders, ", "))
				if config.MaxAge > 0 {
					w.Header().Set("Access-Control-Max-Age",
						string(rune(config.MaxAge)))
				}
				w.WriteHeader(http.StatusNoContent)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

func main() {
	config := NewCORSConfig()

	mux := http.NewServeMux()
	mux.HandleFunc("/api/profile", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]string{"status": "ok"})
	})

	handler := ProductionCORSMiddleware(config)(mux)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      handler,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Println("Starting secure server on :8080")
	log.Fatal(server.ListenAndServe())
}
```

**Defense in Depth Layers**:

1. **URL Validation Layer**:
```go
// Reject malformed origins that could bypass checks
parsedURL, err := url.Parse(origin)
if err != nil || parsedURL.Scheme == "" {
    return false, "invalid_url"
}
// Reject origins with paths/queries (potential bypass)
if parsedURL.Path != "" && parsedURL.Path != "/" {
    return false, "origin_has_path"
}
```

2. **Anchored Regex Patterns**:
```go
// WRONG: Unanchored regex allows bypass
pattern := regexp.MustCompile(`\.example\.com`)
// Matches: https://example.com.attacker.com !

// CORRECT: Fully anchored with strict subdomain rules
pattern := regexp.MustCompile(`^https://[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?\.app\.example\.com$`)
```

3. **Cache Poisoning Prevention**:
```go
// Always set Vary headers to prevent cached responses
// from being served to different origins
w.Header().Add("Vary", "Origin")
w.Header().Add("Vary", "Access-Control-Request-Method")
w.Header().Add("Vary", "Access-Control-Request-Headers")
```

**Additional Protections**:

- **HTTPS enforcement**: Reject HTTP origins in production to prevent MitM attacks
- **Audit logging**: All CORS decisions logged with client context for security monitoring and incident response
- **Subdomain validation**: Strict regex patterns prevent attacks like `https://evil-example.com` or `https://example.com.evil.com`
- **Normalization**: Origins are lowercased and trimmed to prevent case-sensitivity bypasses
- **No wildcard with credentials**: Never combine `Access-Control-Allow-Origin: *` with `Allow-Credentials: true`
- **Rate limiting**: Implement at the load balancer level for preflight requests to prevent DoS
